import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate(); // For handling card clicks

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  // Function to handle actions when a card is clicked
  const handleCardAction = (type) => {
    if (type === 'payments') {
      // You can redirect to a specific 'How it works' or 'Security' page
      alert("Redirecting to our Secure Payment Policy...");
      // navigate('/security'); 
    } else if (type === 'students') {
      // Redirect to the freelancers/services list
      navigate('/services');
    } else if (type === 'delivery') {
      // Open contact or FAQ
      navigate('/contact');
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '80vh',
          padding: '80px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-2 fw-bold mb-3" style={{ letterSpacing: '-2px', textShadow: '2px 4px 10px rgba(0,0,0,0.2)' }}>
            Web <span style={{ color: '#ffc107' }}>Development</span>
          </h1>
          <p className="lead fs-4 mb-5 opacity-75 mx-auto" style={{ maxWidth: '800px' }}>
            The ultimate marketplace for students to showcase skills and clients to find top-tier web solutions.
          </p>
          <div className="d-flex justify-content-center gap-3 flex-wrap">
            <Link to="/services" className="btn btn-warning btn-lg px-5 py-3 fw-bold rounded-pill shadow-lg border-0">
              Explore Services
            </Link>
            <Link to="/contact" className="btn btn-outline-light btn-lg px-5 py-3 rounded-pill border-2">
              Contact Us
            </Link> 
          </div>
        </div>
      </header>

      {/* 2. Interactive Features Section */}
      <section className="py-5 bg-white">
        <div className="container py-5">
          <div className="text-center mb-5">
            <h2 className="fw-bold display-5 text-dark">Why Choose Us?</h2>
            <div className="mx-auto mt-2" style={{ width: '70px', height: '5px', background: '#ffc107', borderRadius: '10px' }}></div>
            <p className="text-muted mt-3">Click on a card to learn more about our features.</p>
          </div>
          
          <div className="row g-4 text-center">
            {/* Card 1: Secure Payments */}
            <div className="col-md-4" onClick={() => handleCardAction('payments')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">🛡️</div>
                <h4 className="fw-bold text-dark">Secure Payments</h4>
                <p className="text-muted">Safe escrow-based transactions for every single project.</p>
                <span className="text-primary fw-bold small">Learn More →</span>
              </div>
            </div>

            {/* Card 2: Verified Students */}
            <div className="col-md-4" onClick={() => handleCardAction('students')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">🎓</div>
                <h4 className="fw-bold text-dark">Verified Students</h4>
                <p className="text-muted">Work with top-rated talent from verified educational backgrounds.</p>
                <span className="text-primary fw-bold small">Browse Talent →</span>
              </div>
            </div>

            {/* Card 3: Fast Delivery */}
            <div className="col-md-4" onClick={() => handleCardAction('delivery')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">⚡</div>
                <h4 className="fw-bold text-dark">Fast Delivery</h4>
                <p className="text-muted">Optimized workflows to ensure your projects are delivered on time.</p>
                <span className="text-primary fw-bold small">Our Guarantee →</span>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Nashik Location Section */}
      <section id="contact" className="py-5" style={{ backgroundColor: '#f8f9fa' }}>
        <div className="container text-center">
          <h2 className="fw-bold mb-5 display-6">📍 Visit Our Hub in <span className="text-primary">Nashik</span></h2>
          <div className="shadow-lg rounded-5 overflow-hidden mx-auto border-white border-5" style={{ maxWidth: '1100px', height: '450px' }}>
            <iframe
              title="Nashik Map"
              src="https://www.google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      {/* Internal CSS for the Premium Look */}
      <style>{`
        .interactive-card { 
          transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
          background: #ffffff;
        }
        .interactive-card:hover { 
          transform: translateY(-15px); 
          box-shadow: 0 30px 60px rgba(0,0,0,0.12) !important;
          background: #fdfdfd;
        }
        .interactive-card:active {
          transform: scale(0.96);
        }
        .btn:hover {
          transform: translateY(-3px);
          filter: brightness(1.1);
        }
      `}</style>

    </div>
  );
}

export default Home;
